def fromfluxgettemp(flux,hpfluxandtemp):
    #get one hp temperature data from heat flux
    #Limit the minimum and maximum values of input heat flux.
    if flux<=hpfluxandtemp[0 ][1 ]:
        flux=hpfluxandtemp[0 ][1 ]
        return hpfluxandtemp[0 ][0 ]
    if flux>=hpfluxandtemp[-1 ][1 ]:
        #flux=hpfluxandtemp[-1 ][1 ]
        return min(1000000,(flux-hpfluxandtemp[ -1 ][ 1 ])*(hpfluxandtemp[ -1 ][ 0 ]-hpfluxandtemp[ -4 ][ 0 ])/(hpfluxandtemp[ -1 ][ 1 ]-hpfluxandtemp[ -4 ][ 1 ])+hpfluxandtemp[ -1 ][ 0 ])
    for i in range(len(hpfluxandtemp)):
        if flux<=hpfluxandtemp[i ][1 ]:
            return (flux - hpfluxandtemp[ i - 1 ][1 ]) * (hpfluxandtemp[i ][0 ] - hpfluxandtemp[ i - 1 ][0 ]) / (hpfluxandtemp[i ][1 ] - hpfluxandtemp[ i - 1 ][1 ]) + hpfluxandtemp[ i - 1 ][0 ]
        else:pass

def getheatpipetemp(hpflux,origin_hptemp,loseHp,heatpipe_type=[]):
    inthpflux=[]
    for i in hpflux:
        inthpflux.append(abs(int(i)))
    hp_temp=[]
    for i in range(len(hpflux)):
        if i in loseHp:
            if abs(hpflux[ i ]) > 10:
                hp_temp.append( origin_hptemp[ i ] + hpflux[ i ] * 0.05)
                # print(hp_temp[ i ], hpflux[ i ])
            else:
                hp_temp.append(origin_hptemp[ i ])
        else:

            hp_temp.append(fromfluxgettemp(hpflux[i], total_hpdata[heatpipe_type[i]]) / 100 - 300)


    hp_temp=np.asarray(hp_temp)
    return hp_temp

